  getPlaces(): Observable<Place[]> { return of(this.MOCK_PLACES); }
  getPlacesByCategory(category: Category): Observable<Place[]> { return of(this.MOCK_PLACES.filter(p => p.category === category)); }
  getPlacesByWilaya(wilaya: string): Observable<Place[]> { return of(this.MOCK_PLACES.filter(p => p.wilaya === wilaya)); }
  getFeaturedPlaces(): Observable<Place[]> { return of(this.MOCK_PLACES.filter(p => p.isFeatured).slice(0, 12)); }
  getPlaceById(id: string): Observable<Place | undefined> { return of(this.MOCK_PLACES.find(p => p.id === id)); }
  getTopPlaces(limit = 10): Observable<Place[]> { return of([...this.MOCK_PLACES].sort((a, b) => b.popularity - a.popularity).slice(0, limit)); }
  getPlacesSortedByRating(limit = 50): Observable<Place[]> { return of([...this.MOCK_PLACES].sort((a, b) => (b.googleRating ?? 0) - (a.googleRating ?? 0)).slice(0, limit)); }
  getNearbyPlaces(lat: number, lng: number, radiusKm: number): Observable<Place[]> { return of(this.MOCK_PLACES.filter(p => { const d = this.haversine(lat, lng, p.latitude, p.longitude); return d <= radiusKm; })); }
  getCategoryCount(category: Category): number { return this.MOCK_PLACES.filter(p => p.category === category).length; }
  getAllWilayas(): string[] { return [...new Set(this.MOCK_PLACES.map(p => p.wilaya))].sort(); }
  searchPlaces(query: string): Observable<Place[]> { const q = query.toLowerCase(); return of(this.MOCK_PLACES.filter(p => p.nameFr.toLowerCase().includes(q) || p.wilaya.toLowerCase().includes(q) || p.description.toLowerCase().includes(q) || p.category.toLowerCase().includes(q))); }
  private haversine(lat1: number, lng1: number, lat2: number, lng2: number): number { const R = 6371; const dLat = (lat2 - lat1) * Math.PI / 180; const dLng = (lng2 - lng1) * Math.PI / 180; const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLng/2)**2; return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)); }
